import{c as a,Q as t,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Reflexion: Language Agents with Verbal Reinforcement Learning","description":"","frontmatter":{"title":"Reflexion: Language Agents with Verbal Reinforcement Learning","authors":"Noah Shinn, Federico Cassano et al.","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2303.11366-reflexion-arxiv.md","filePath":"research/agent-harness/references/2303.11366-reflexion-arxiv.md","lastUpdated":1779901665000}'),o={name:"research/agent-harness/references/2303.11366-reflexion-arxiv.md"};function i(l,e,s,h,d,c){return t(),r("div",null,[...e[0]||(e[0]=[n(`<h1 id="reflexion-language-agents-with-verbal-reinforcement-learning" tabindex="-1">Reflexion: Language Agents with Verbal Reinforcement Learning <a class="header-anchor" href="#reflexion-language-agents-with-verbal-reinforcement-learning" aria-label="Permalink to &quot;Reflexion: Language Agents with Verbal Reinforcement Learning&quot;">​</a></h1><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2303.11366" target="_blank" rel="noreferrer">https://arxiv.org/abs/2303.11366</a></li><li><strong>發表</strong>: NeurIPS 2023</li><li><strong>作者</strong>: Noah Shinn, Federico Cassano et al.</li><li><strong>收錄日期</strong>: 2026-05-01</li><li><strong>重要性</strong>: Priority A — ReAct 最重要的直接延伸；引入「言語強化學習」不需要更新模型權重</li></ul><hr><h2 id="核心創新-突破-react-的限制" tabindex="-1">核心創新：突破 ReAct 的限制 <a class="header-anchor" href="#核心創新-突破-react-的限制" aria-label="Permalink to &quot;核心創新：突破 ReAct 的限制&quot;">​</a></h2><p>ReAct 的問題：每次執行是獨立的，無法從過去失敗中學習。</p><p>Reflexion 解法：引入「言語反思迴圈」——任務完成後，agent 生成文字化的反思，下次嘗試時自動注入這些反思作為 context。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>嘗試 1 → 失敗 → 反思（&quot;我錯在了 X，下次應該 Y&quot;）</span></span>
<span class="line"><span>  ↓（反思存入 long-term memory）</span></span>
<span class="line"><span>嘗試 2 → 帶著反思重試 → 改進</span></span></code></pre></div><hr><h2 id="技術架構" tabindex="-1">技術架構 <a class="header-anchor" href="#技術架構" aria-label="Permalink to &quot;技術架構&quot;">​</a></h2><h3 id="三層結構" tabindex="-1">三層結構 <a class="header-anchor" href="#三層結構" aria-label="Permalink to &quot;三層結構&quot;">​</a></h3><ol><li><strong>Actor</strong>: 執行任務的 LLM（使用 ReAct 或 Chain-of-Thought）</li><li><strong>Evaluator</strong>: 評估 Actor 輸出的模型（外部回饋 or 內部 LLM 評判）</li><li><strong>Self-Reflection</strong>: 生成言語化反思並存入 episodic memory</li></ol><h3 id="記憶組件" tabindex="-1">記憶組件 <a class="header-anchor" href="#記憶組件" aria-label="Permalink to &quot;記憶組件&quot;">​</a></h3><ul><li><strong>Short-term memory</strong>: 當前 sliding context window（軌跡 + 反思）</li><li><strong>Long-term memory</strong>: 外部向量存儲（可選）</li><li><strong>Episodic memory</strong>: 保存過去試驗的具體反思</li></ul><hr><h2 id="實驗成果" tabindex="-1">實驗成果 <a class="header-anchor" href="#實驗成果" aria-label="Permalink to &quot;實驗成果&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Benchmark</th><th>Reflexion</th><th>基線（純 ReAct）</th></tr></thead><tbody><tr><td>HumanEval 編碼</td><td><strong>91% pass@1</strong></td><td>~80%（GPT-4 當時）</td></tr><tr><td>AlfWorld 環境</td><td>97%</td><td>~85%</td></tr><tr><td>HotPotQA 問答</td><td>超越 CoT</td><td>baseline</td></tr></tbody></table><hr><h2 id="對-harness-engineering-的影響" tabindex="-1">對 Harness Engineering 的影響 <a class="header-anchor" href="#對-harness-engineering-的影響" aria-label="Permalink to &quot;對 Harness Engineering 的影響&quot;">​</a></h2><h3 id="洞見-1-反思機制是-long-running-agent-的必要條件" tabindex="-1">洞見 #1：反思機制是 long-running agent 的必要條件 <a class="header-anchor" href="#洞見-1-反思機制是-long-running-agent-的必要條件" aria-label="Permalink to &quot;洞見 #1：反思機制是 long-running agent 的必要條件&quot;">​</a></h3><p>移除反思組件的後果（Generative Agents 實驗）：</p><ul><li>48 小時內從多日規劃退化為重複的無狀態回應</li><li>證明記憶 + 反思是維持 agent 行為品質的核心機制</li></ul><h3 id="洞見-2-evaluator-必須與-actor-分離" tabindex="-1">洞見 #2：Evaluator 必須與 Actor 分離 <a class="header-anchor" href="#洞見-2-evaluator-必須與-actor-分離" aria-label="Permalink to &quot;洞見 #2：Evaluator 必須與 Actor 分離&quot;">​</a></h3><p>Actor 評估自己的輸出會產生「自我稱讚偏差」（self-congratulatory bias）。Reflexion 的三層架構正式建立了這個分離原則，後來被 AHE 的「決策可觀測性」和 Anthropic 的 Planner-Generator-Evaluator 架構繼承。</p><h3 id="洞見-3-失敗可以被「語言化」為知識" tabindex="-1">洞見 #3：失敗可以被「語言化」為知識 <a class="header-anchor" href="#洞見-3-失敗可以被「語言化」為知識" aria-label="Permalink to &quot;洞見 #3：失敗可以被「語言化」為知識&quot;">​</a></h3><p>不需要梯度更新，只需把失敗的原因用文字描述清楚，下一次就能改進。這是 Ratchet 原則（每個失敗沉澱成永久規則）的學術驗證。</p><hr><h2 id="與本-workspace-的對應" tabindex="-1">與本 Workspace 的對應 <a class="header-anchor" href="#與本-workspace-的對應" aria-label="Permalink to &quot;與本 Workspace 的對應&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Reflexion 概念</th><th>Workspace 實現</th></tr></thead><tbody><tr><td>Episodic memory（失敗反思）</td><td>Known Gotchas section in each Skill</td></tr><tr><td>Evaluator 分離</td><td>/deep-review skill + security-reviewer agent</td></tr><tr><td>Verbal reinforcement</td><td>CLAUDE.md 規則（每條都源自具體失敗）</td></tr><tr><td>Long-term memory</td><td>Auto Memory（~/.claude/projects/）</td></tr></tbody></table><hr><h2 id="延伸論文" tabindex="-1">延伸論文 <a class="header-anchor" href="#延伸論文" aria-label="Permalink to &quot;延伸論文&quot;">​</a></h2><ul><li>LATS（2310.04406）：將 Reflexion 升級為樹狀搜索</li><li>Agent Q（2408.07199）：加入 MCTS + DPO 強化學習</li><li>SE-Agent（2508.02085）：軌跡排名與競爭機制</li></ul><h2 id="參考連結" tabindex="-1">參考連結 <a class="header-anchor" href="#參考連結" aria-label="Permalink to &quot;參考連結&quot;">​</a></h2><ul><li>arXiv: <a href="https://arxiv.org/abs/2303.11366" target="_blank" rel="noreferrer">https://arxiv.org/abs/2303.11366</a></li></ul>`,33)])])}const p=a(o,[["render",i]]);export{u as __pageData,p as default};
